INSERT INTO "couple_info" ("id", "bride_name", "groom_name", "bride_photo", "groom_photo", "bride_description", "groom_description", "our_story", "wedding_date", "hero_image", "created_at", "updated_at") VALUES ('eada6bee-d939-4026-90f8-72ae6f58b222', 'Xuân Lâm', 'Xuân Lợi', 'data:image/jpeg;base64,', 'data:image/jpeg;base64,', 'Cô dâu Xuân Lâm- Người phụ nữ dịu dàng, xinh đẹp và tài năng. Cô là một giáo viên mầm non với tấm lòng nhân hậu và luôn yêu thương trẻ em.', 'Chú rể Xuân Lợi - Chàng trai lịch lãm, tài giỏi và có trách nhiệm. Anh là kỹ sư phần mềm với niềm đam mê công nghệ và khát vọng xây dựng tương lai tươi sáng.', 'Chúng tôi gặp nhau vào một buổi chiều xuân ấm áp tại công viên Hồ Gươm. Từ ánh mắt đầu tiên, chúng tôi đã biết rằng đây là duyên phận trời định. Sau 3 năm bên nhau, chúng tôi quyết định bước vào hôn nhân để cùng nhau xây dựng một tổ ấm hạnh phúc.r', '2025-11-08T00:00:00.000Z', 'data:image/jpeg;base64,', '2025-10-24T23:43:14.676Z', '2025-10-24T23:45:35.392Z');
